    public void loginWithCredentials(String email, String password) {
        enterEmail(email);
        enterPassword(password);
        clickLoginButton();
    }

    public void loginAs(String roleName) {
        var creds = getLoginDataByRole(roleName);
        loginWithCredentials(creds.get("Username"), creds.get("Password"));
    }

